function normalize(value:string){
  return value.replace(/\r\n/g,'\n');
}

const appliedMarkers:[string,string][]=[
  ['shared/src/index.ts','BUILDING_VISIBILITY_ZONES'],
  ['server/src/rooms/Drop8Room.ts','updateBuildingStates'],
  ['client/src/main.ts','fieldChatCollapsed'],
  ['docs/PATCH_NOTES.md','## Refactor 005B'],
];
if(appliedMarkers.every(([relative,marker])=>{
  const target=path.join(root,relative);
  return fs.existsSync(target)&&normalize(fs.readFileSync(target,'utf8')).includes(marker);
})){
  console.log('DROP 8 Refactor 005B는 이미 적용되어 있습니다.');
  console.log('다음 실행: pnpm typecheck && pnpm lint && pnpm test && pnpm build && pnpm dev:lan');
  process.exit(0);
}

function findBlock(lines:string[],block:string[],near:number){
  if(block.length===0)return Math.max(0,Math.min(lines.length,near));
  const matches:number[]=[];
  outer:for(let i=0;i<=lines.length-block.length;i++){
    for(let j=0;j<block.length;j++){
      if(lines[i+j]!==block[j])continue outer;
    }
    matches.push(i);
  }
  if(!matches.length)return -1;
  return matches.reduce((best,value)=>Math.abs(value-near)<Math.abs(best-near)?value:best,matches[0]!);
}

function applyUnified(relative:string,diff:string){
  const target=path.join(root,relative);
  if(!fs.existsSync(target))throw new Error(`필수 파일 없음: ${relative}`);
  const raw=normalize(fs.readFileSync(target,'utf8'));
  const hadFinalNewline=raw.endsWith('\n');
  let lines=raw.split('\n');
  if(lines.at(-1)==='')lines.pop();

  const diffLines=normalize(diff).split('\n');
  let index=0;
  let offset=0;
  while(index<diffLines.length){
    const header=diffLines[index];
    if(!header?.startsWith('@@')){index++;continue;}
    const match=/@@ -(\d+)(?:,(\d+))? \+(\d+)(?:,(\d+))? @@/.exec(header);
    if(!match)throw new Error(`잘못된 패치 hunk: ${relative} / ${header}`);
    const expected=Number(match[1])-1+offset;
    index++;

    const oldBlock:string[]=[];
    const newBlock:string[]=[];
    while(index<diffLines.length&&!diffLines[index]!.startsWith('@@')){
      const line=diffLines[index]!;
      if(line.startsWith('--- ')||line.startsWith('+++ ')){index++;continue;}
      if(line.startsWith(' ')){oldBlock.push(line.slice(1));newBlock.push(line.slice(1));}
      else if(line.startsWith('-'))oldBlock.push(line.slice(1));
      else if(line.startsWith('+'))newBlock.push(line.slice(1));
      else if(line.startsWith('\\ No newline at end of file')){/* ignore */}
      index++;
    }

    const at=findBlock(lines,oldBlock,expected);
    if(at<0){
      const already=findBlock(lines,newBlock,expected);
      if(already>=0)continue;
      throw new Error(`패치 기준 불일치: ${relative} / hunk ${match[1]}. Refactor 005 적용 상태를 확인하세요.`);
    }
    lines.splice(at,oldBlock.length,...newBlock);
    offset+=newBlock.length-oldBlock.length;
  }
  fs.writeFileSync(target,lines.join('\n')+(hadFinalNewline?'\n':''),'utf8');
}

const requiredMarkers:[string,string][]=[
  ['client/src/GameScene.ts','remoteBuffers'],
  ['client/src/GameScene.ts','drawTransportPlane'],
  ['client/src/network.ts','serverTickAvg'],
  ['client/src/style.css','REFACTOR_005_VISIBILITY_MINIMAP_PERF'],
  ['server/src/rooms/Drop8Room.ts','createNextZone'],
  ['server/src/rooms/Drop8Room.ts','serverTickAvg'],
  ['server/src/rooms/schema.ts','serverTickAvg'],
  ['shared/src/index.ts','WORLD_PROPS'],
  ['shared/src/index.ts','createPlaneRoute'],
  ['docs/PATCH_NOTES.md','Refactor 005'],
];

for(const [relative,marker] of requiredMarkers){
  const target=path.join(root,relative);
  if(!fs.existsSync(target)||!normalize(fs.readFileSync(target,'utf8')).includes(marker)){
    throw new Error(`Refactor 005 기준 파일이 아닙니다: ${relative} / ${marker}`);
  }
}

const targets=[...Object.keys(patches),...Object.keys(newFiles)];
fs.mkdirSync(backupRoot,{recursive:true});
for(const relative of targets){
  const source=path.join(root,relative);
  if(!fs.existsSync(source))continue;
  const destination=path.join(backupRoot,relative);
  if(fs.existsSync(destination))continue;
  fs.mkdirSync(path.dirname(destination),{recursive:true});
  fs.copyFileSync(source,destination);
}

for(const [relative,diff] of Object.entries(patches))applyUnified(relative,diff);
for(const [relative,content] of Object.entries(newFiles)){
  const target=path.join(root,relative);
  if(fs.existsSync(target)){
    const current=normalize(fs.readFileSync(target,'utf8'));
    if(current!==normalize(content))throw new Error(`새 파일 충돌: ${relative}`);
    continue;
  }
  fs.mkdirSync(path.dirname(target),{recursive:true});
  fs.writeFileSync(target,content,'utf8');
}

